const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "postgresql",
  "inlineSchema": "// ============================================================\n// Pocket Mint — Personal Finance Tracker\n// Prisma Schema for PostgreSQL (Supabase)\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  // Output must match the path imported by src/lib/prisma.ts\n  // ('../generated/prisma/client', which resolves to this directory's shim).\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─────────────────────────────────────────────\n// USER\n// ─────────────────────────────────────────────\nmodel User {\n  id        String   @id @default(cuid())\n  email     String   @unique\n  name      String\n  // NOTE: no password column. Authentication is owned entirely by Supabase Auth;\n  // this backend never stores, hashes, or verifies passwords. Local users are\n  // linked to the verified Supabase identity via `id` (the JWT `sub` claim).\n  avatarUrl String?  @map(\"avatar_url\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  wallets                       Wallet[]\n  categories                    Category[]\n  transactions                  Transaction[]\n  installments                  Installment[]\n  recurringTransactionTemplates RecurringTransactionTemplate[]\n  savingGoals                   SavingGoal[]\n  budgets                       Budget[]\n\n  @@map(\"users\")\n}\n\n// ─────────────────────────────────────────────\n// WALLET  (rekening / e-wallet / paylater)\n// ─────────────────────────────────────────────\nenum WalletType {\n  CASH\n  BANK\n  E_WALLET\n  CREDIT_CARD\n  PAYLATER\n  LOAN\n}\n\nmodel Wallet {\n  id             String       @id @default(cuid())\n  userId         String       @map(\"user_id\")\n  name           String\n  type           WalletType   @default(CASH)\n  balance        Decimal      @default(0) @db.Decimal(15, 2)\n  creditLimit    Decimal      @default(0) @map(\"credit_limit\") @db.Decimal(15, 2)\n  initialBalance Decimal      @default(0) @map(\"initial_balance\") @db.Decimal(15, 2)\n  icon           String?\n  color          String?\n  interestRate   Decimal      @default(0) @map(\"interest_rate\") @db.Decimal(5, 2)\n  // Bunga flat per bulan dalam persen (contoh: 2.95 = 2.95%)\n  // Default 0 untuk wallet tipe ASSET\n  isArchived     Boolean      @default(false) @map(\"is_archived\")\n  adminFee       Decimal      @default(0) @map(\"admin_fee\") @db.Decimal(15, 2)\n  // Biaya admin default untuk wallet ini\n  // FLAT    → nilai dalam Rupiah (contoh: 45000)\n  // PERCENT → nilai dalam persen (contoh: 1.5 = 1.5%)\n  adminFeeType   AdminFeeType @default(FLAT) @map(\"admin_fee_type\")\n  // Tipe kalkulasi biaya admin\n  cutoffDay      Int?         @map(\"cutoff_day\")\n  paymentDueDay  Int?         @map(\"payment_due_day\")\n  createdAt      DateTime     @default(now()) @map(\"created_at\")\n  updatedAt      DateTime     @updatedAt @map(\"updated_at\")\n\n  // Relations\n  user                          User                           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  transactions                  Transaction[]                  @relation(\"WalletTransactions\")\n  // Transfers whose destination is this wallet (Transaction.toWalletId).\n  toTransactions                Transaction[]                  @relation(\"WalletToTransactions\")\n  installments                  Installment[]\n  recurringTransactionTemplates RecurringTransactionTemplate[]\n\n  @@index([userId])\n  @@map(\"wallets\")\n}\n\n// ─────────────────────────────────────────────\n// CATEGORY  (kategori transaksi)\n// ─────────────────────────────────────────────\nenum CategoryType {\n  INCOME\n  EXPENSE\n}\n\nmodel Category {\n  id        String       @id @default(cuid())\n  userId    String       @map(\"user_id\")\n  name      String\n  type      CategoryType\n  icon      String?\n  color     String?\n  createdAt DateTime     @default(now()) @map(\"created_at\")\n  updatedAt DateTime     @updatedAt @map(\"updated_at\")\n\n  // Relations\n  user                          User                           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  transactions                  Transaction[]\n  recurringTransactionTemplates RecurringTransactionTemplate[]\n  budgets                       Budget[]\n\n  @@unique([userId, name, type])\n  @@index([userId, type])\n  @@map(\"categories\")\n}\n\n// ─────────────────────────────────────────────\n// TRANSACTION  (income / expense / transfer)\n// ─────────────────────────────────────────────\nenum TransactionType {\n  INCOME\n  EXPENSE\n  TRANSFER\n}\n\nmodel Transaction {\n  id            String          @id @default(cuid())\n  userId        String          @map(\"user_id\")\n  walletId      String          @map(\"wallet_id\")\n  // Destination wallet for TRANSFER rows. Persisting it makes a transfer\n  // self-describing so update/delete can reverse BOTH sides from the stored\n  // row (not from request data). Null for INCOME/EXPENSE and legacy transfers.\n  toWalletId    String?         @map(\"to_wallet_id\")\n  categoryId    String?         @map(\"category_id\")\n  type          TransactionType\n  amount        Decimal         @db.Decimal(15, 2)\n  description   String?\n  isInstallment Boolean         @default(false) @map(\"is_installment\")\n  installmentId String?         @map(\"installment_id\")\n  date          DateTime\n  createdAt     DateTime        @default(now()) @map(\"created_at\")\n  updatedAt     DateTime        @updatedAt @map(\"updated_at\")\n\n  // Relations\n  user          User                    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  wallet        Wallet                  @relation(\"WalletTransactions\", fields: [walletId], references: [id], onDelete: Cascade)\n  toWallet      Wallet?                 @relation(\"WalletToTransactions\", fields: [toWalletId], references: [id], onDelete: SetNull)\n  category      Category?               @relation(fields: [categoryId], references: [id], onDelete: SetNull)\n  installment   Installment?            @relation(fields: [installmentId], references: [id], onDelete: SetNull)\n  reminderEvent RecurringReminderEvent?\n\n  @@index([userId, date])\n  @@index([userId, type])\n  @@index([walletId, date])\n  @@index([toWalletId])\n  @@index([categoryId])\n  @@index([installmentId])\n  @@map(\"transactions\")\n}\n\n// ─────────────────────────────────────────────\n// INSTALLMENT  (cicilan)\n// ─────────────────────────────────────────────\n// ─────────────────────────────────────────────\n// ADMIN FEE TYPE\n// ─────────────────────────────────────────────\nenum AdminFeeType {\n  FLAT // nominal tetap dalam Rupiah\n  PERCENT // persentase dari pokok transaksi\n}\n\nenum InstallmentStatus {\n  ACTIVE\n  SETTLED\n  CANCELLED\n}\n\nenum BillKind {\n  FULL\n  INSTALLMENT\n}\n\nmodel Installment {\n  id                String            @id @default(cuid())\n  userId            String            @map(\"user_id\")\n  walletId          String            @map(\"wallet_id\")\n  totalAmount       Decimal           @map(\"total_amount\") @db.Decimal(15, 2)\n  interestRate      Decimal           @default(0) @map(\"interest_rate\") @db.Decimal(5, 2)\n  // Snapshot bunga saat transaksi cicilan dibuat\n  totalInterest     Decimal           @default(0) @map(\"total_interest\") @db.Decimal(15, 2)\n  // Total bunga = amount × (interest_rate/100) × installmentMonths\n  adminFee          Decimal           @default(0) @map(\"admin_fee\") @db.Decimal(15, 2)\n  // Snapshot nilai admin_fee saat transaksi dibuat\n  adminFeeType      AdminFeeType      @default(FLAT) @map(\"admin_fee_type\")\n  // Snapshot tipe admin fee saat transaksi dibuat\n  totalAdminFee     Decimal           @default(0) @map(\"total_admin_fee\") @db.Decimal(15, 2)\n  // Hasil kalkulasi aktual:\n  // FLAT    → sama dengan admin_fee\n  // PERCENT → amount × (admin_fee / 100)\n  grandTotal        Decimal           @default(0) @map(\"grand_total\") @db.Decimal(15, 2)\n  // Total yang harus dibayar = amount + total_interest + total_admin_fee\n  installmentMonths Int               @map(\"installment_months\")\n  currentTerm       Int               @default(1) @map(\"current_term\")\n  monthlyAmount     Decimal           @map(\"monthly_amount\") @db.Decimal(15, 2)\n  kind              BillKind          @default(INSTALLMENT)\n  paidTerms         Int               @default(0) @map(\"paid_terms\")\n  nextDueDate       DateTime          @map(\"next_due_date\")\n  status            InstallmentStatus @default(ACTIVE)\n  startDate         DateTime          @map(\"start_date\")\n  description       String?\n  balanceDeducted   Boolean           @default(false) @map(\"balance_deducted\")\n  createdAt         DateTime          @default(now()) @map(\"created_at\")\n  updatedAt         DateTime          @updatedAt @map(\"updated_at\")\n\n  // Relations\n  user           User                     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  wallet         Wallet                   @relation(fields: [walletId], references: [id], onDelete: Cascade)\n  transactions   Transaction[]\n  reminderEvents RecurringReminderEvent[]\n\n  @@index([userId, status])\n  @@index([walletId])\n  @@map(\"installments\")\n}\n\n// ─────────────────────────────────────────────\n// RECURRING TRANSACTION TEMPLATE  (transaksi rutin)\n// ─────────────────────────────────────────────\nenum RecurrenceFrequency {\n  DAILY\n  WEEKLY\n  MONTHLY\n  YEARLY\n}\n\nenum RecurringAmountMode {\n  FIXED\n  FLEXIBLE\n}\n\nmodel RecurringTransactionTemplate {\n  id                 String              @id @default(cuid())\n  userId             String              @map(\"user_id\")\n  walletId           String              @map(\"wallet_id\")\n  categoryId         String?             @map(\"category_id\")\n  name               String\n  type               TransactionType\n  amountMode         RecurringAmountMode @default(FIXED) @map(\"amount_mode\")\n  amount             Decimal?            @db.Decimal(15, 2)\n  description        String?\n  frequency          RecurrenceFrequency\n  startDate          DateTime            @map(\"start_date\")\n  endDate            DateTime?           @map(\"end_date\")\n  isActive           Boolean             @default(true) @map(\"is_active\")\n  reminderEnabled    Boolean             @default(false) @map(\"reminder_enabled\")\n  reminderOffsetDays Int?                @map(\"reminder_offset_days\")\n  createdAt          DateTime            @default(now()) @map(\"created_at\")\n  updatedAt          DateTime            @updatedAt @map(\"updated_at\")\n\n  // Relations\n  user           User                     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  wallet         Wallet                   @relation(fields: [walletId], references: [id], onDelete: Cascade)\n  category       Category?                @relation(fields: [categoryId], references: [id], onDelete: SetNull)\n  reminderEvents RecurringReminderEvent[]\n\n  @@index([userId, isActive])\n  @@map(\"recurring_transaction_templates\")\n}\n\n// Phase 4: one row per (template, occurrence, offset) that the reminder engine\n// has already fired — the unique constraint is what makes re-running the\n// engine for the same evaluation date a no-op instead of a duplicate.\n// Phase 7: a row is sourced from either a recurring template OR an\n// installment, never both — templateId/installmentId are each optional so\n// the same table serves both without a parallel pipeline. The engine is the\n// only writer and is responsible for setting exactly one of them.\nmodel RecurringReminderEvent {\n  id                     String    @id @default(cuid())\n  templateId             String?   @map(\"template_id\")\n  installmentId          String?   @map(\"installment_id\")\n  userId                 String    @map(\"user_id\")\n  occurrenceDate         DateTime  @map(\"occurrence_date\")\n  offsetDays             Int       @map(\"offset_days\")\n  reminderDate           DateTime  @map(\"reminder_date\")\n  readAt                 DateTime? @map(\"read_at\")\n  // Phase 6: NULL = still waiting: non-null = a real transaction was created\n  // from this reminder and it must never be processed again. Template-sourced\n  // rows only — installment-sourced completion is derived, see notification\n  // controller.\n  completedAt            DateTime? @map(\"completed_at\")\n  generatedTransactionId String?   @unique @map(\"generated_transaction_id\")\n  createdAt              DateTime  @default(now()) @map(\"created_at\")\n\n  template             RecurringTransactionTemplate? @relation(fields: [templateId], references: [id], onDelete: Cascade)\n  installment          Installment?                  @relation(fields: [installmentId], references: [id], onDelete: Cascade)\n  generatedTransaction Transaction?                  @relation(fields: [generatedTransactionId], references: [id], onDelete: SetNull)\n\n  @@unique([templateId, occurrenceDate, offsetDays])\n  @@unique([installmentId, occurrenceDate, offsetDays])\n  @@index([userId, reminderDate])\n  @@map(\"recurring_reminder_events\")\n}\n\n// ─────────────────────────────────────────────\n// SAVING GOAL  (target tabungan)\n// ─────────────────────────────────────────────\n// Phase 8: a planning/tracking record only — it never creates a transaction,\n// mutates a wallet balance, or affects net worth. Progress is stored directly\n// on the row (currentAmount) with no contribution ledger; see\n// financial-logic.skill.md before adding one.\nenum SavingGoalStatus {\n  ACTIVE\n  COMPLETED\n  ARCHIVED\n}\n\nmodel SavingGoal {\n  id            String           @id @default(cuid())\n  userId        String           @map(\"user_id\")\n  name          String\n  targetAmount  Decimal          @map(\"target_amount\") @db.Decimal(15, 2)\n  currentAmount Decimal          @default(0) @map(\"current_amount\") @db.Decimal(15, 2)\n  targetDate    DateTime?        @map(\"target_date\")\n  notes         String?\n  status        SavingGoalStatus @default(ACTIVE)\n  createdAt     DateTime         @default(now()) @map(\"created_at\")\n  updatedAt     DateTime         @updatedAt @map(\"updated_at\")\n\n  // Relations\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId, status])\n  @@map(\"saving_goals\")\n}\n\n// ─────────────────────────────────────────────\n// BUDGET  (anggaran)\n// ─────────────────────────────────────────────\n// Phase A (PD-009, Approved): a recurring monthly spend-limit definition per\n// user and expense Category — not a period-specific snapshot. Usage (spent,\n// remaining, percentUsed, status) is always derived at read time from posted\n// Transaction rows for the current reporting month; nothing is cached here.\n// One persistent Budget per (userId, categoryId), archived or not — archiving\n// does not free the category for a second Budget (PD-009 Decision L).\n// Category expense-eligibility (categoryId must reference an EXPENSE-type\n// Category owned by the same user) is enforced by the service layer, not the\n// database, matching PD-009 Decision D.\nmodel Budget {\n  id         String   @id @default(cuid())\n  userId     String   @map(\"user_id\")\n  categoryId String   @map(\"category_id\")\n  amount     Decimal  @db.Decimal(15, 2)\n  isArchived Boolean  @default(false) @map(\"is_archived\")\n  createdAt  DateTime @default(now()) @map(\"created_at\")\n  updatedAt  DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  user     User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  category Category @relation(fields: [categoryId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, categoryId])\n  @@index([userId, isArchived])\n  @@map(\"budgets\")\n}\n"
}

